"use client";

import * as React from "react";
import * as THREE from "three";

import { cn } from "@/lib/utils";
import { clamp01, damp, useExperienceViewport, usePrefersReducedMotion } from "@/components/experience/experience-runtime";
import { useWebGLStage } from "@/components/experience/use-webgl-stage";

export type DistortionCarouselItem = {
  id: string;
  src: string;
  mobileSrc?: string;
  tabletSrc?: string;
  alt: string;
};

export type DistortionCarouselProps<T extends DistortionCarouselItem = DistortionCarouselItem> = Omit<React.ComponentProps<"section">, "children"> & {
  label: string;
  items: T[];
  startIndex?: number;
  /** Strength of the velocity-driven bend, chromatic shift and zoom. */
  distortion?: number;
  /** How quickly the strip settles onto a slide. */
  smoothing?: number;
  /** Horizontal drag distance (in stage widths) that equals one slide. */
  dragSensitivity?: number;
  maxDpr?: number;
  previousLabel?: string;
  nextLabel?: string;
  slideLabel?: (index: number, total: number) => string;
  showDots?: boolean;
  renderCaption?: (item: T, index: number, active: boolean) => React.ReactNode;
  children?: React.ReactNode;
  onActiveChange?: (index: number) => void;
  stageClassName?: string;
  canvasClassName?: string;
  fallback?: React.ReactNode;
};

const VERTEX = /* glsl */ `
  varying vec2 vUv;
  void main() { vUv = uv; gl_Position = vec4(position, 1.); }
`;

const FRAGMENT = /* glsl */ `
  precision highp float;
  varying vec2 vUv;
  uniform sampler2D uFrom;
  uniform sampler2D uTo;
  uniform vec2 uResolution;
  uniform vec2 uFromSize;
  uniform vec2 uToSize;
  uniform float uMix;
  uniform float uVelocity;
  uniform float uDistortion;

  vec2 coverUv(vec2 uv, vec2 imageSize) {
    float screenAspect = uResolution.x / max(1., uResolution.y);
    float imageAspect = imageSize.x / max(1., imageSize.y);
    vec2 scale = screenAspect < imageAspect
      ? vec2(screenAspect / imageAspect, 1.)
      : vec2(1., imageAspect / screenAspect);
    return (uv - .5) * scale + .5;
  }

  void main() {
    float speed = clamp(uVelocity, -1., 1.);
    float energy = abs(speed);
    // Velocity bends the image and pulls it slightly toward the camera.
    vec2 uv = vUv;
    uv.x += sin(uv.y * 5.2 + speed * 2.4) * speed * .045 * uDistortion;
    uv = (uv - .5) * (1. - energy * .06 * uDistortion) + .5;
    // Slide parallax: the outgoing image leads, the incoming one catches up.
    float shift = .22 * uDistortion;
    vec2 fromUv = coverUv(uv + vec2(uMix * shift, 0.), uFromSize);
    vec2 toUv = coverUv(uv - vec2((1. - uMix) * shift, 0.), uToSize);
    vec2 aberration = vec2(speed * .014 * uDistortion, 0.);
    vec3 fromColor;
    fromColor.r = texture2D(uFrom, fromUv + aberration).r;
    fromColor.g = texture2D(uFrom, fromUv).g;
    fromColor.b = texture2D(uFrom, fromUv - aberration).b;
    vec3 toColor;
    toColor.r = texture2D(uTo, toUv + aberration).r;
    toColor.g = texture2D(uTo, toUv).g;
    toColor.b = texture2D(uTo, toUv - aberration).b;
    float blend = smoothstep(.12, .88, uMix);
    vec3 color = mix(fromColor, toColor, blend);
    color *= 1. - energy * .12;
    gl_FragColor = vec4(color, 1.);
  }
`;

/**
 * A draggable WebGL image carousel: momentum, snap, and a velocity-driven
 * bend/chromatic distortion while the strip is moving. Touch drags work
 * (vertical page scroll stays native); reduced motion and WebGL failures get
 * a native snap rail.
 */
export function DistortionCarousel<T extends DistortionCarouselItem = DistortionCarouselItem>({
  canvasClassName,
  children,
  className,
  distortion = 1,
  dragSensitivity = 1,
  fallback,
  items,
  label,
  maxDpr = 1.6,
  nextLabel = "Next slide",
  onActiveChange,
  previousLabel = "Previous slide",
  renderCaption,
  showDots = true,
  slideLabel = (index, total) => `Slide ${index + 1} of ${total}`,
  smoothing = 7,
  stageClassName,
  startIndex = 0,
  ...props
}: DistortionCarouselProps<T>) {
  const stageRef = React.useRef<HTMLDivElement>(null);
  const canvasRef = React.useRef<HTMLCanvasElement>(null);
  const total = items.length;
  const lastIndex = Math.max(0, total - 1);
  const initialIndex = Math.min(lastIndex, Math.max(0, startIndex));

  const offsetRef = React.useRef(initialIndex);
  const targetRef = React.useRef(initialIndex);
  const velocityRef = React.useRef(0);
  const dragRef = React.useRef({ active: false, pointerId: -1, startX: 0, startOffset: 0, lastX: 0, lastTime: 0, speed: 0 });
  const [activeIndex, setActiveIndex] = React.useState(initialIndex);
  const activeIndexRef = React.useRef(initialIndex);
  const reducedMotion = usePrefersReducedMotion();
  const viewport = useExperienceViewport();
  const resolveSrc = React.useCallback((item: T) => viewport === "mobile"
    ? item.mobileSrc ?? item.tabletSrc ?? item.src
    : viewport === "tablet"
      ? item.tabletSrc ?? item.src
      : item.src, [viewport]);

  const onActiveChangeRef = React.useRef(onActiveChange);
  React.useInsertionEffect(() => {
    onActiveChangeRef.current = onActiveChange;
  });
  React.useEffect(() => {
    onActiveChangeRef.current?.(activeIndex);
  }, [activeIndex]);

  const goTo = React.useCallback(
    (index: number) => {
      const next = Math.min(lastIndex, Math.max(0, index));
      targetRef.current = next;
      // Explicit navigation reflects immediately in captions/dots; the strip
      // itself settles over the following frames.
      if (activeIndexRef.current !== next) {
        activeIndexRef.current = next;
        setActiveIndex(next);
      }
    },
    [lastIndex],
  );

  const { ready, failed } = useWebGLStage({
    stageRef,
    canvasRef,
    enabled: !reducedMotion && total > 0,
    maxDpr,
    signature: JSON.stringify([distortion, smoothing, items.map(resolveSrc), viewport]),
    create: ({ renderer, markReady, markFailed, isDisposed, requestResize }) => {
      const scene = new THREE.Scene();
      const camera = new THREE.Camera();
      const geometry = new THREE.PlaneGeometry(2, 2);
      const loader = new THREE.TextureLoader();
      const textures: Array<THREE.Texture | null> = items.map(() => null);
      const pending = new Set<number>();
      const empty = new THREE.Texture();
      const uniforms = {
        uFrom: { value: empty as THREE.Texture },
        uTo: { value: empty as THREE.Texture },
        uResolution: { value: new THREE.Vector2(1, 1) },
        uFromSize: { value: new THREE.Vector2(1, 1) },
        uToSize: { value: new THREE.Vector2(1, 1) },
        uMix: { value: 0 },
        uVelocity: { value: 0 },
        uDistortion: { value: distortion },
      };
      const material = new THREE.ShaderMaterial({ vertexShader: VERTEX, fragmentShader: FRAGMENT, uniforms, depthTest: false, depthWrite: false });
      scene.add(new THREE.Mesh(geometry, material));

      const ensureTexture = (index: number) => {
        if (index < 0 || index >= items.length || textures[index] || pending.has(index)) return;
        pending.add(index);
        loader.load(
          resolveSrc(items[index]!),
          (texture) => {
            pending.delete(index);
            if (isDisposed()) {
              texture.dispose();
              return;
            }
            texture.colorSpace = THREE.SRGBColorSpace;
            texture.minFilter = THREE.LinearFilter;
            texture.magFilter = THREE.LinearFilter;
            textures[index] = texture;
            if (index === Math.round(offsetRef.current)) {
              requestResize();
              markReady();
            }
          },
          undefined,
          () => {
            pending.delete(index);
            if (index === initialIndex) markFailed();
          },
        );
      };
      ensureTexture(initialIndex);
      ensureTexture(initialIndex + 1);
      ensureTexture(initialIndex - 1);

      const applyTexture = (slot: "uFrom" | "uTo", sizeSlot: "uFromSize" | "uToSize", index: number) => {
        const texture = textures[Math.min(lastIndex, Math.max(0, index))];
        if (!texture) return;
        uniforms[slot].value = texture;
        const image = texture.image as { width?: number; height?: number };
        uniforms[sizeSlot].value.set(image.width ?? 1, image.height ?? 1);
      };

      return {
        onResize: (width, height) => {
          uniforms.uResolution.value.set(width, height);
          renderer.render(scene, camera);
        },
        onFrame: (delta) => {
          const drag = dragRef.current;
          const settle = drag.active ? smoothing * 2.2 : smoothing;
          const previous = offsetRef.current;
          offsetRef.current = damp(previous, targetRef.current, settle, delta);
          const frameVelocity = (offsetRef.current - previous) / Math.max(0.001, delta);
          velocityRef.current = damp(velocityRef.current, frameVelocity * 0.34, 9, delta);

          const floor = Math.min(lastIndex - (total > 1 ? 1 : 0), Math.max(0, Math.floor(offsetRef.current)));
          ensureTexture(floor - 1);
          ensureTexture(floor);
          ensureTexture(floor + 1);
          ensureTexture(floor + 2);
          applyTexture("uFrom", "uFromSize", floor);
          applyTexture("uTo", "uToSize", floor + 1);
          uniforms.uMix.value = clamp01(offsetRef.current - floor);
          uniforms.uVelocity.value = Math.max(-1, Math.min(1, velocityRef.current));
          renderer.render(scene, camera);

          const settled = Math.round(targetRef.current);
          if (settled !== activeIndexRef.current) {
            activeIndexRef.current = settled;
            setActiveIndex(settled);
          }
        },
        dispose: () => {
          textures.forEach((texture) => texture?.dispose());
          empty.dispose();
          geometry.dispose();
          material.dispose();
        },
      };
    },
  });

  const handlePointerDown = (event: React.PointerEvent<HTMLDivElement>) => {
    if (reducedMotion || failed || total < 2) return;
    // Never start a drag from the arrows/dots (or any interactive child):
    // pointer capture would retarget the pointerup and swallow their click.
    if ((event.target as Element | null)?.closest?.("button, a, input, select, textarea")) return;
    const drag = dragRef.current;
    drag.active = true;
    drag.pointerId = event.pointerId;
    drag.startX = event.clientX;
    drag.startOffset = targetRef.current;
    drag.lastX = event.clientX;
    drag.lastTime = performance.now();
    drag.speed = 0;
    event.currentTarget.setPointerCapture(event.pointerId);
  };
  const handlePointerMove = (event: React.PointerEvent<HTMLDivElement>) => {
    const drag = dragRef.current;
    if (!drag.active || event.pointerId !== drag.pointerId) return;
    const stage = stageRef.current;
    const width = Math.max(1, stage?.clientWidth ?? 1);
    const deltaSlides = ((event.clientX - drag.startX) / width) * dragSensitivity * 1.4;
    const raw = drag.startOffset - deltaSlides;
    // Rubber-band beyond the first and last slide.
    const clamped = Math.min(lastIndex, Math.max(0, raw));
    targetRef.current = clamped + (raw - clamped) * 0.25;
    const now = performance.now();
    const elapsed = Math.max(8, now - drag.lastTime);
    drag.speed = ((drag.lastX - event.clientX) / width) * (1000 / elapsed);
    drag.lastX = event.clientX;
    drag.lastTime = now;
  };
  const endDrag = () => {
    const drag = dragRef.current;
    if (!drag.active) return;
    drag.active = false;
    const projected = targetRef.current + drag.speed * 0.32 * dragSensitivity;
    targetRef.current = Math.min(lastIndex, Math.max(0, Math.round(projected)));
  };
  const handleKeyDown = (event: React.KeyboardEvent<HTMLDivElement>) => {
    if (event.key === "ArrowLeft") {
      event.preventDefault();
      goTo(Math.round(targetRef.current) - 1);
    } else if (event.key === "ArrowRight") {
      event.preventDefault();
      goTo(Math.round(targetRef.current) + 1);
    }
  };

  const staticMode = reducedMotion || failed;
  const activeItem = items[Math.min(lastIndex, Math.max(0, activeIndex))];

  return (
    <section aria-label={label} data-distortion-carousel data-experience-viewport={viewport} data-ready={ready || undefined} data-fallback={staticMode || undefined} className={cn("relative isolate overflow-hidden bg-black", className)} {...props}>
      {staticMode ? (
        fallback ?? (
          <ul className="flex h-full snap-x snap-mandatory gap-3 overflow-x-auto">
            {items.map((item, index) => (
              <li key={item.id} className="relative h-full w-[88%] shrink-0 snap-center overflow-hidden">
                {/* eslint-disable-next-line @next/next/no-img-element -- registry source stays framework-neutral. */}
                <img alt={item.alt} src={resolveSrc(item)} className="size-full object-cover" loading={index > 1 ? "lazy" : undefined} />
                {renderCaption?.(item, index, index === activeIndex)}
              </li>
            ))}
          </ul>
        )
      ) : (
        <div
          ref={stageRef}
          role="group"
          aria-roledescription="carousel"
          aria-label={label}
          tabIndex={0}
          className={cn("absolute inset-0 cursor-grab touch-pan-y select-none focus-visible:outline-2 focus-visible:-outline-offset-2 active:cursor-grabbing", stageClassName)}
          onPointerDown={handlePointerDown}
          onPointerMove={handlePointerMove}
          onPointerUp={endDrag}
          onPointerCancel={endDrag}
          onKeyDown={handleKeyDown}
        >
          <canvas ref={canvasRef} aria-hidden className={cn("absolute inset-0 size-full transition-opacity duration-500", ready ? "opacity-100" : "opacity-0", canvasClassName)} />
          <span aria-live="polite" className="sr-only">
            {activeItem ? `${slideLabel(activeIndex, total)}. ${activeItem.alt}` : null}
          </span>
          {renderCaption ? (
            <div className="pointer-events-none absolute inset-0">
              {items.map((item, index) => (
                <div key={item.id} aria-hidden={index !== activeIndex} className={cn("absolute inset-0 transition-opacity duration-500", index === activeIndex ? "opacity-100" : "opacity-0")}>
                  {renderCaption(item, index, index === activeIndex)}
                </div>
              ))}
            </div>
          ) : null}
          {total > 1 ? (
            <div className="absolute inset-x-0 bottom-5 flex items-center justify-center gap-4">
              {/* ui-primitive-allow-native: canvas-overlay arrow with bespoke styling. */}<button type="button" aria-label={previousLabel} disabled={activeIndex <= 0} onClick={() => goTo(activeIndex - 1)} className="pointer-events-auto flex size-11 cursor-pointer items-center justify-center rounded-full border border-white/25 bg-black/30 text-white backdrop-blur transition-colors hover:bg-black/55 disabled:cursor-default disabled:opacity-35">
                <svg aria-hidden viewBox="0 0 24 24" className="size-4" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M15 6l-6 6 6 6" /></svg>
              </button>
              {showDots ? (
                <div className="flex items-center gap-2">
                  {items.map((item, index) => (
                    <React.Fragment key={item.id}>
                      {/* ui-primitive-allow-native: carousel dot with 44px touch target. */}<button type="button" aria-label={slideLabel(index, total)} aria-current={index === activeIndex || undefined} onClick={() => goTo(index)} className={cn("relative size-11 cursor-pointer rounded-full before:absolute before:left-1/2 before:top-1/2 before:h-2 before:-translate-x-1/2 before:-translate-y-1/2 before:rounded-full before:transition-all", index === activeIndex ? "before:w-6 before:bg-white" : "before:w-2 before:bg-white/40 hover:before:bg-white/70")} />
                    </React.Fragment>
                  ))}
                </div>
              ) : null}
              {/* ui-primitive-allow-native: canvas-overlay arrow with bespoke styling. */}<button type="button" aria-label={nextLabel} disabled={activeIndex >= lastIndex} onClick={() => goTo(activeIndex + 1)} className="pointer-events-auto flex size-11 cursor-pointer items-center justify-center rounded-full border border-white/25 bg-black/30 text-white backdrop-blur transition-colors hover:bg-black/55 disabled:cursor-default disabled:opacity-35">
                <svg aria-hidden viewBox="0 0 24 24" className="size-4" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M9 6l6 6-6 6" /></svg>
              </button>
            </div>
          ) : null}
        </div>
      )}
      {children}
    </section>
  );
}

"use client";

import * as React from "react";

export const EXPERIENCE_BREAKPOINTS = {
  tablet: 640,
  desktop: 1025,
} as const;

export type ExperienceViewport = "mobile" | "tablet" | "desktop";

export type ExperienceResponsiveValue<T> = T | {
  /** Mobile-first value, also used during SSR/hydration. */
  mobile: T;
  /** iPad/tablet value. Falls back to `mobile` when omitted. */
  tablet?: T;
  /** Wide-screen value. Falls back to `tablet`, then `mobile`. */
  desktop?: T;
};

const subscribeToHydration = () => () => undefined;

export function useHydrated() {
  return React.useSyncExternalStore(subscribeToHydration, () => true, () => false);
}

export function useMediaQuery(query: string, serverValue = false) {
  const subscribe = React.useCallback(
    (onChange: () => void) => {
      const media = window.matchMedia(query);
      media.addEventListener("change", onChange);
      return () => media.removeEventListener("change", onChange);
    },
    [query],
  );
  const getSnapshot = React.useCallback(() => window.matchMedia(query).matches, [query]);
  return React.useSyncExternalStore(subscribe, getSnapshot, () => serverValue);
}

/**
 * Hydration-safe reduced-motion preference: false on the server and during
 * hydration, then live. Replaces the repeated `mounted && useReducedMotion()`
 * pattern.
 */
export function usePrefersReducedMotion() {
  return useMediaQuery("(prefers-reduced-motion: reduce)");
}

/** True on touch-first devices; use to swap pointer effects for static or rail modes. */
export function useCoarsePointer() {
  return useMediaQuery("(pointer: coarse)");
}

/** True only when a hover-capable precise pointer is present. */
export function useFinePointer() {
  return useMediaQuery("(hover: hover) and (pointer: fine)");
}

/**
 * Shared mobile-first viewport contract for every experience primitive.
 *
 * Mobile: < 640px · tablet/iPad: 640–1024px · desktop: >= 1025px.
 * Pointer capability remains a separate signal because an iPad can gain a
 * trackpad without changing its layout profile.
 */
export function useExperienceViewport(): ExperienceViewport {
  const tablet = useMediaQuery(`(min-width: ${EXPERIENCE_BREAKPOINTS.tablet}px)`);
  const desktop = useMediaQuery(`(min-width: ${EXPERIENCE_BREAKPOINTS.desktop}px)`);
  if (desktop) return "desktop";
  if (tablet) return "tablet";
  return "mobile";
}

export function resolveExperienceValue<T>(
  value: ExperienceResponsiveValue<T>,
  viewport: ExperienceViewport,
): T {
  if (typeof value !== "object" || value === null || !("mobile" in value)) return value;
  if (viewport === "desktop") return value.desktop ?? value.tablet ?? value.mobile;
  if (viewport === "tablet") return value.tablet ?? value.mobile;
  return value.mobile;
}

/** Conservative raster/WebGL supersampling budget for each layout profile. */
export function getExperienceDprCap(width: number) {
  if (width < EXPERIENCE_BREAKPOINTS.tablet) return 1;
  if (width < EXPERIENCE_BREAKPOINTS.desktop) return 1.25;
  return 1.6;
}

export function clamp01(value: number) {
  return Math.min(1, Math.max(0, value));
}

export function mix(from: number, to: number, amount: number) {
  return from + (to - from) * amount;
}

export function damp(current: number, target: number, smoothing: number, deltaSeconds: number) {
  return mix(current, target, 1 - Math.exp(-Math.max(0.01, smoothing) * deltaSeconds));
}

/** Returns the frames sorted by `at`, reusing the input when it is already ordered. */
export function sortKeyframes<T extends { at: number }>(frames: T[]): T[] {
  for (let index = 1; index < frames.length; index += 1) {
    if (frames[index - 1]!.at > frames[index]!.at) {
      return [...frames].sort((left, right) => left.at - right.at);
    }
  }
  return frames;
}

export function resolveKeyframes<T extends { at: number }>(
  frames: T[],
  progress: number,
): { from: T; to: T; mix: number } {
  if (frames.length === 0) throw new Error("Experience keyframes cannot be empty.");
  const sorted = sortKeyframes(frames);
  if (progress <= sorted[0]!.at) return { from: sorted[0]!, to: sorted[0]!, mix: 0 };
  for (let index = 0; index < sorted.length - 1; index += 1) {
    const from = sorted[index]!;
    const to = sorted[index + 1]!;
    if (progress <= to.at) {
      const span = Math.max(0.0001, to.at - from.at);
      return { from, to, mix: clamp01((progress - from.at) / span) };
    }
  }
  const final = sorted.at(-1)!;
  return { from: final, to: final, mix: 0 };
}

export function supportsWebGL() {
  try {
    const canvas = document.createElement("canvas");
    return Boolean(
      canvas.getContext("webgl2", { failIfMajorPerformanceCaveat: true })
      || canvas.getContext("webgl", { failIfMajorPerformanceCaveat: true }),
    );
  } catch {
    return false;
  }
}

"use client";

import * as React from "react";
import * as THREE from "three";

import {
  getExperienceDprCap,
  supportsWebGL,
} from "@/components/experience/experience-runtime";

export type WebGLStageContext = {
  renderer: THREE.WebGLRenderer;
  stage: HTMLElement;
  canvas: HTMLCanvasElement;
  /** Flip the stage to ready once async assets are decoded and the first frame can show. */
  markReady: () => void;
  /** Flip the stage to failed (poster/fallback becomes visible). */
  markFailed: () => void;
  /** True after the stage effect has been cleaned up; guard async callbacks with it. */
  isDisposed: () => boolean;
  /** Re-run the resize pass — call after async assets load so size-dependent caps apply. */
  requestResize: () => void;
};

export type WebGLStageHandle = {
  /** Runs every animation frame while the stage is on screen, the tab is visible and the context is alive. */
  onFrame?: (deltaSeconds: number, time: number) => void;
  /** Runs after the renderer resized; update cameras, uniforms and derived scales here. */
  onResize?: (width: number, height: number) => void;
  /** Optional extra cap on device pixel ratio for a given stage size (e.g. never supersample past the source texture). */
  getDpr?: (width: number, height: number) => number;
  /** Dispose geometries, materials and textures created in `create`; the renderer itself is disposed by the hook. */
  dispose?: () => void;
};

export type WebGLStageOptions = {
  stageRef: React.RefObject<HTMLElement | null>;
  canvasRef: React.RefObject<HTMLCanvasElement | null>;
  /** false keeps the stage fully inert — use it for reduced-motion / coarse-pointer static modes. */
  enabled: boolean;
  maxDpr?: number;
  antialias?: boolean;
  alpha?: boolean;
  /** Request a stencil buffer (three defaults it off since r163); needed for aperture/mask scenes. */
  stencil?: boolean;
  /**
   * Serialize every visual prop that must rebuild the scene into this string.
   * Array or callback identity never triggers a rebuild, so inline props stay safe.
   */
  signature?: string;
  /** Root margin for the offscreen pause observer. */
  rootMargin?: string;
  /** Build the scene. Reads props freely (latest values are visible via closure on each rebuild). */
  create: (context: WebGLStageContext) => WebGLStageHandle | void;
};

/**
 * Shared WebGL lifecycle for experience stages: renderer with capped DPR,
 * resize + offscreen observers, a visibility-gated animation loop, context-loss
 * pause with context-restore recovery, and full disposal. Components own only
 * their scene graph and per-frame logic.
 */
export function useWebGLStage({
  alpha = false,
  antialias = false,
  canvasRef,
  create,
  enabled,
  maxDpr = 1.6,
  rootMargin = "20% 0px",
  signature,
  stageRef,
  stencil = false,
}: WebGLStageOptions) {
  const [ready, setReady] = React.useState(false);
  const [failed, setFailed] = React.useState(false);
  const createRef = React.useRef(create);
  React.useInsertionEffect(() => {
    createRef.current = create;
  });

  React.useEffect(() => {
    const stage = stageRef.current;
    const canvas = canvasRef.current;
    if (!stage || !canvas || !enabled) return;
    if (!supportsWebGL()) {
      const timer = window.setTimeout(() => setFailed(true), 0);
      return () => window.clearTimeout(timer);
    }

    let disposed = false;
    let frame = 0;
    let previous = performance.now();
    let contextAlive = true;
    let lossTimer = 0;
    let onScreen = true;

    const renderer = new THREE.WebGLRenderer({ canvas, antialias, alpha, stencil, powerPreference: "high-performance" });
    renderer.outputColorSpace = THREE.SRGBColorSpace;
    renderer.setPixelRatio(Math.min(
      window.devicePixelRatio || 1,
      maxDpr,
      getExperienceDprCap(stage.clientWidth),
    ));

    let handle: WebGLStageHandle = {};
    const resize = () => {
      const width = Math.max(1, stage.clientWidth);
      const height = Math.max(1, stage.clientHeight);
      const extraCap = handle.getDpr?.(width, height) ?? Number.POSITIVE_INFINITY;
      renderer.setPixelRatio(Math.max(0.5, Math.min(
        window.devicePixelRatio || 1,
        maxDpr,
        extraCap,
        getExperienceDprCap(width),
      )));
      renderer.setSize(width, height, false);
      handle.onResize?.(width, height);
    };
    const context: WebGLStageContext = {
      renderer,
      stage,
      canvas,
      markReady: () => {
        if (!disposed) setReady(true);
      },
      markFailed: () => {
        if (!disposed) setFailed(true);
      },
      isDisposed: () => disposed,
      requestResize: () => {
        if (!disposed) resize();
      },
    };
    handle = createRef.current(context) ?? {};
    const resizeObserver = new ResizeObserver(resize);
    resizeObserver.observe(stage);

    const intersectionObserver = new IntersectionObserver(
      ([entry]) => {
        onScreen = Boolean(entry?.isIntersecting);
      },
      { rootMargin },
    );
    intersectionObserver.observe(stage);

    // preventDefault opts into restoration; Three re-uploads retained resources
    // on the next render after the context returns. Only a loss that never
    // restores becomes a visible failure.
    const contextLost = (event: Event) => {
      event.preventDefault();
      contextAlive = false;
      window.clearTimeout(lossTimer);
      lossTimer = window.setTimeout(() => {
        if (!disposed && !contextAlive) setFailed(true);
      }, 2500);
    };
    const contextRestored = () => {
      window.clearTimeout(lossTimer);
      contextAlive = true;
      if (disposed) return;
      setFailed(false);
      resize();
    };
    canvas.addEventListener("webglcontextlost", contextLost);
    canvas.addEventListener("webglcontextrestored", contextRestored);

    const render = (time: number) => {
      if (disposed) return;
      const delta = Math.min(0.05, Math.max(0.001, (time - previous) / 1000));
      previous = time;
      if (contextAlive && onScreen && document.visibilityState === "visible") {
        handle.onFrame?.(delta, time);
      }
      frame = requestAnimationFrame(render);
    };

    resize();
    frame = requestAnimationFrame(render);

    return () => {
      disposed = true;
      cancelAnimationFrame(frame);
      window.clearTimeout(lossTimer);
      resizeObserver.disconnect();
      intersectionObserver.disconnect();
      canvas.removeEventListener("webglcontextlost", contextLost);
      canvas.removeEventListener("webglcontextrestored", contextRestored);
      handle.dispose?.();
      renderer.dispose();
    };
  }, [alpha, antialias, canvasRef, enabled, maxDpr, rootMargin, signature, stageRef, stencil]);

  return { ready, failed };
}
